using SkiaSharp;

try
{
    using var bitmap = new SKBitmap(100, 100);
    using var canvas = new SKCanvas(bitmap);
    using var paint = new SKPaint { Color = SKColors.Red, IsAntialias = true };
    canvas.Clear(SKColors.White);
    canvas.DrawCircle(50, 50, 40, paint);
    var pixel = bitmap.GetPixel(50, 50);
    Console.WriteLine($"SkiaSharp version: {typeof(SKBitmap).Assembly.GetName().Version}");
    Console.WriteLine($"Center pixel: R={pixel.Red}, G={pixel.Green}, B={pixel.Blue}, A={pixel.Alpha}");
    if (pixel.Red > 200 && pixel.Green < 50 && pixel.Blue < 50)
        Console.WriteLine("SUCCESS: Core SkiaSharp rendering works correctly");
    else
        Console.WriteLine($"UNEXPECTED: Pixel values unexpected: {pixel}");
}
catch (Exception ex)
{
    Console.WriteLine($"ERROR: {ex.GetType().Name}: {ex.Message}");
    Console.WriteLine(ex.StackTrace);
}
